module t;
  logic clk = 0;
  initial forever #1 clk = ~clk;

  event e;
  int cyc = 0;

  always @(posedge clk) begin
    cyc <= cyc + 1;
    $display("[%0t] Triggered event", $time);
    ->e;
    if (cyc == 2) begin
      $write("*-* All Finished *-*\n");
      $finish;
    end
  end

  assert property (@(e) 1 |=> 1) $display("[%0t] Implication fullfilled", $time);
endmodule
```

Where `1 |=> 1` should be interpreted as:

```verilog
 1 ##1 `true |-> 1
```

But currently uses `$past` as:

```verilog
1 | $past(1, @e)
```

Per IEEE 1800-2023 16.12.7 Implication:


        Therefore,
             sequence_expr |=> property_expr
        is equivalent to the following:
             sequence_expr ##1 `true |-> property_expr

